import javafx.application.Application;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class CSSStylingExample extends Application {
    @Override
    public void start(Stage primaryStage) {
        VBox root = new VBox(15);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);

        // 1. Inline CSS
        Label title = new Label("CSS Styling in JavaFX");
        title.setStyle(
            "-fx-font-size: 24px; " +
            "-fx-font-weight: bold; " +
            "-fx-text-fill: #2c3e50; " +
            "-fx-padding: 10px;"
        );
        root.getChildren().add(title);

        // 2. Styled button
        Button styledBtn = new Button("Styled Button");
        styledBtn.setStyle(
            "-fx-background-color: #3498db; " +
            "-fx-text-fill: white; " +
            "-fx-font-size: 14px; " +
            "-fx-padding: 10px 20px; " +
            "-fx-background-radius: 5px;"
        );
        root.getChildren().add(styledBtn);

        // 3. Styled with hover effect
        Button hoverBtn = new Button("Hover Me!");
        hoverBtn.setStyle(
            "-fx-background-color: #e74c3c; " +
            "-fx-text-fill: white; " +
            "-fx-font-size: 14px; " +
            "-fx-padding: 10px 20px; " +
            "-fx-background-radius: 5px;"
        );
        // Pseudo-class :hover
        hoverBtn.setOnMouseEntered(e -> {
            hoverBtn.setStyle(
                "-fx-background-color: #c0392b; " +
                "-fx-text-fill: white; " +
                "-fx-font-size: 14px; " +
                "-fx-padding: 10px 20px; " +
                "-fx-background-radius: 5px;"
            );
        });
        hoverBtn.setOnMouseExited(e -> {
            hoverBtn.setStyle(
                "-fx-background-color: #e74c3c; " +
                "-fx-text-fill: white; " +
                "-fx-font-size: 14px; " +
                "-fx-padding: 10px 20px; " +
                "-fx-background-radius: 5px;"
            );
        });
        root.getChildren().add(hoverBtn);

        // 4. Styled TextField
        TextField styledField = new TextField();
        styledField.setPromptText("Enter text...");
        styledField.setStyle(
            "-fx-background-color: #ecf0f1; " +
            "-fx-border-color: #bdc3c7; " +
            "-fx-border-width: 2px; " +
            "-fx-border-radius: 5px; " +
            "-fx-padding: 8px; " +
            "-fx-font-size: 14px;"
        );
        styledField.setMaxWidth(250);
        root.getChildren().add(styledField);

        // 5. Styled Label
        Label styledLabel = new Label("This is a styled label");
        styledLabel.setStyle(
            "-fx-font-size: 16px; " +
            "-fx-text-fill: #27ae60; " +
            "-fx-font-style: italic; " +
            "-fx-background-color: #f0f0f0; " +
            "-fx-padding: 10px; " +
            "-fx-border-color: #27ae60; " +
            "-fx-border-width: 2px; " +
            "-fx-border-radius: 5px;"
        );
        root.getChildren().add(styledLabel);

        // 6. CheckBox with custom style
        CheckBox styledCheck = new CheckBox("Styled CheckBox");
        styledCheck.setStyle(
            "-fx-font-size: 14px; " +
            "-fx-text-fill: #2c3e50; " +
            "-fx-padding: 5px;"
        );
        root.getChildren().add(styledCheck);

        // 7. Multiple classes via CSS (would use external stylesheet)
        // But we'll demonstrate with inline

        // 8. Combined styles
        VBox styledBox = new VBox(10);
        styledBox.setAlignment(Pos.CENTER);
        styledBox.setStyle(
            "-fx-background-color: #f8f9fa; " +
            "-fx-border-color: #dee2e6; " +
            "-fx-border-width: 2px; " +
            "-fx-border-radius: 10px; " +
            "-fx-padding: 20px; " +
            "-fx-effect: dropshadow(gaussian, rgba(0,0,0,0.1), 10, 0, 0, 5);"
        );

        Label boxLabel = new Label("Styled Container");
        boxLabel.setStyle("-fx-font-size: 18px; -fx-font-weight: bold;");
        Button boxBtn = new Button("Inside Container");
        boxBtn.setStyle(
            "-fx-background-color: #28a745; " +
            "-fx-text-fill: white; " +
            "-fx-padding: 8px 16px; " +
            "-fx-background-radius: 5px;"
        );

        styledBox.getChildren().addAll(boxLabel, boxBtn);
        root.getChildren().add(styledBox);

        // 9. External stylesheet example (commented - for reference)
        // scene.getStylesheets().add(getClass().getResource("styles.css").toExternalForm());

        Scene scene = new Scene(root, 500, 650);

        primaryStage.setTitle("CSS Styling in JavaFX");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

