import javafx.application.Application;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.TextField;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class CSSPractice extends Application {
    @Override
    public void start(Stage primaryStage) {
        VBox root = new VBox(15);
        root.setAlignment(Pos.CENTER);
        root.setStyle("-fx-background-color: #f5f5f5; -fx-padding: 20px;");

        Label label = new Label("Styled Label");
        label.setStyle(
            "-fx-font-size: 18px; " +
            "-fx-font-weight: bold; " +
            "-fx-text-fill: blue; " +
            "-fx-padding: 10px;"
        );

        Button button = new Button("Styled Button");
        button.setStyle(
            "-fx-background-color: green; " +
            "-fx-text-fill: white; " +
            "-fx-padding: 10px 20px; " +
            "-fx-background-radius: 5px;"
        );

        TextField textField = new TextField();
        textField.setPromptText("Enter text...");
        textField.setStyle(
            "-fx-background-color: #f0f0f0; " +
            "-fx-border-color: #cccccc; " +
            "-fx-padding: 8px; " +
            "-fx-border-radius: 3px;"
        );
        textField.setMaxWidth(200);

        root.getChildren().addAll(label, button, textField);

        Scene scene = new Scene(root, 400, 300);
        primaryStage.setTitle("CSS Practice");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}
